// src/pages/ForecastPage.jsx
import React, { useEffect, useState } from "react";
import forecastApi from "../api/forecastApi";
import NumberInput from "../components/NumberInput";

function ForecastPage() {
  const [period, setPeriod] = useState("2026-W03");
  const [rows, setRows] = useState([]);
  const [message, setMessage] = useState("");

  // small form fields
  const [newProductId, setNewProductId] = useState(1);
  const [newGradePackId, setNewGradePackId] = useState(1);
  const [newQty, setNewQty] = useState(0);

  useEffect(() => {
    async function load() {
      const data = await forecastApi.getByPeriod(period);
      setRows(data);
    }
    load();
  }, [period]);

  const handleAddLine = () => {
    if (!newQty || newQty <= 0) return;
    const newRow = {
      product_id: newProductId,
      grade_pack_id: newGradePackId,
      forecast_qty: newQty
    };
    setRows([newRow, ...rows]);
    setNewQty(0);
  };

  const handleSave = async () => {
    await forecastApi.save(period, rows);
    setMessage("Forecast saved");
  };

  return (
    <div>
      <h2>Demand Forecast</h2>

      <div style={{ marginBottom: 8 }}>
        <label>
          Period:
          <input
            value={period}
            onChange={(e) => setPeriod(e.target.value)}
            style={{ marginLeft: 6 }}
          />
        </label>
      </div>

      {/* Create Forecast Line */}
      <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
        <NumberInput
          value={newProductId}
          onChange={setNewProductId}
          min={1}
        />
        <NumberInput
          value={newGradePackId}
          onChange={setNewGradePackId}
          min={1}
        />
        <NumberInput
          value={newQty}
          onChange={setNewQty}
          min={0}
        />
        <button onClick={handleAddLine}>Add Row</button>
      </div>

      {/* Existing forecast lines */}
      <table className="pp-table">
        <thead>
          <tr>
            <th>Product</th>
            <th>Grade/Pack</th>
            <th>Forecast Qty</th>
            <th />
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.product_id}</td>
              <td>{r.grade_pack_id}</td>
              <td>{r.forecast_qty}</td>
              <td>
                <button
                  onClick={() =>
                    setRows(rows.filter((_, idx) => idx !== i))
                  }
                >
                  X
                </button>
              </td>
            </tr>
          ))}
          {rows.length === 0 && (
            <tr>
              <td colSpan={4}>No forecast lines for this period</td>
            </tr>
          )}
        </tbody>
      </table>

      <button onClick={handleSave} style={{ marginTop: 8 }}>
        Save Forecast
      </button>
      {message && <p>{message}</p>}
    </div>
  );
}

export default ForecastPage;
